#include<bits/stdc++.h>
using namespace std;
long long a[5050],s[5050],dp[5050];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        if(i%2==1)
        {
            s[i]=s[i-1]+a[i/2+1];
        }
        else
        {
            for(long long j=1;j<=(i/2);j++)
            {
                s[i]+=a[j]*2;
            }
        }
    }
    for(long long i=2;i<=n;i++)
    {
        dp[i]=s[i-1];
        for(long long j=1;j<i-2;j++)
        {
            dp[i]=max(dp[i],dp[j+1]+dp[i-1-j]);
        }
    }
    printf("%lld",dp[n]);
    return 0;
}
